// Cambridge Assessment International Education wordmark (PNG, base64).
export const CAMBRIDGE_LOGO_WIDTH = 1094;
export const CAMBRIDGE_LOGO_HEIGHT = 178;
export const CAMBRIDGE_LOGO_B64 = "";
export function cambridgeLogoBytes(): Uint8Array {
  const bin = typeof atob === "function" ? atob(CAMBRIDGE_LOGO_B64) : Buffer.from(CAMBRIDGE_LOGO_B64, "base64").toString("binary");
  const out = new Uint8Array(bin.length);
  for (let i=0;i<bin.length;i++) out[i]=bin.charCodeAt(i);
  return out;
}
